{"name": "Scenario1","cron": "0 22 * * *","period": 100,"code": "triggered_siren := false
triggered_blind := false
triggered_curtain := false
triggered_strobe := false
prev_door_state := (any(#Odd #Door)).doorControl_door
door_count := 0
door_open_time := 0
door_total_open_time := 0
if (((#Window #bottom).windowControl_window == 'open') and (any(#Even #Light).switch_switch == 'on')) {
    (#Siren).sirenMode_setSirenMode('siren')
    triggered_siren = true
}
if (triggered_siren == true and triggered_blind == false) {
    (#Clock).clock_delay(5000)
    (#Blind #bottom).blind_close()
    triggered_blind = true
}
if (triggered_blind == true and triggered_curtain == false) {
    door_state = (any(#Odd #Door)).doorControl_door
    if ((prev_door_state == 'open') and (door_state == 'closed')) {
        door_count = door_count + 1
        door_total_open_time = door_total_open_time + ((#Clock).clock_timestamp() - door_open_time)
    }
    if ((prev_door_state == 'closed') and (door_state == 'open')) {
        door_open_time = (#Clock).clock_timestamp()
    }
    prev_door_state = door_state
    if (door_count >= 2) {
        (#Curtain).curtain_close()
        triggered_curtain = true
    }
}
if (triggered_curtain == true and triggered_strobe == false) {
    strobe_start_time := (#Clock).clock_timestamp()
    (#Alarm).alarm_strobe()
    if ((#Clock).clock_timestamp() - strobe_start_time >= door_total_open_time) {
        (#Alarm).alarm_off()
        triggered_strobe = true
        break
    }
}"}


